//const chatInput = $input.first().json.mensajeUsuario
const chatInput = $('une_data_wpp').first().json.mensajeUsuario


const sessionId = message.from;
//const sessionId = message.from + "_9";
const userName = contact.profile.name || 'Cliente';
const celular = message.from;
const normalizedNumber = celular
  .replace(/^549/, "+54 "); 

// Formatear para el AI Agent
const formattedInput = {
  sessionId: sessionId,
  action: 'sendMessage',
  chatInput: chatInput,
//  etapa_actual,
  userContext: {
    name: userName,
    userId: message.from,
    chatId: message.from, // En WhatsApp el chatId suele ser el mismo que el userId
    phoneNumberId: wppData.metadata.phone_number_id,
    displayPhoneNumber: wppData.metadata.display_phone_number,
    telefono_origen: normalizedNumber,
    messageId: message.id,
    timestamp: message.timestamp,
    platform: 'whatsapp',
  //  contexto_historial: memoria_contexto    
  }
};

return { json: formattedInput };

// Validar y obtener el output del agente
const agentOutput = $input.first().json.output;

// VALIDACIÃN CRÃTICA: Detectar outputs vacÃ­os o invÃĄlidos
const isEmptyOutput = !agentOutput || 
                      agentOutput.trim() === "" || 
                      agentOutput === "(No response was provided)" ||
                      agentOutput.includes("No response was provided");

// Si el output estÃĄ vacÃ­o, generar respuesta de fallback
if (isEmptyOutput) {
  console.error("â ïļ Output vacÃ­o detectado del agente:", agentOutput);

  return [{ 
    json: { 
      output: "DisculpÃĄ, tuve un problema tÃĐcnico procesando tu consulta. ÂŋPodrÃ­as repetir quÃĐ necesitÃĄs? ð",
      error_detected: true,
      original_output: agentOutput
    } 
  }];
}

// Si el output es vÃĄlido, retornarlo tal cual
return [{ 
  json: { 
    output: agentOutput,
    error_detected: false
  } 
}];

const mensajeUsuario = $input.first().json.mensaje_usuario

